trait MyTrait {
    fn method(&self) -> String;
}

struct MyStruct;

impl MyTrait for MyStruct {
    fn method(&self) -> String {
        "Hello".to_string()
    }
}

fn use_trait<T: MyTrait>(item: &T) {
    println!("{}", item.method());
}

fn main() {
    let s = MyStruct;
    use_trait(&s);
}
